// Normaliza el catalogo desde businessConfig y lo pasa como campo unico
// Preserva businessConfig completo (incluye salesConfig, paymentConfig, etc.)
const data = $('Recibir Datos del Router').first().json;
const bc = data.businessConfig || {};
const staticCatalog = bc.catalog || data.catalog || [];
return [{ json: { ...data, catalog: staticCatalog } }];

// Sub-workflow: Ventas
var routerData = $("Recibir Datos del Router").first().json;
var inputNode = $input.first().json;
var input = Object.assign({}, routerData);
// Override message for payment receipt images (bypassed Vision path)
if (inputNode && inputNode.messageOverride) input.message = inputNode.messageOverride;
var businessConfig = input.businessConfig || {};
var salesConfig = businessConfig.salesConfig || {};
var paymentConfig = businessConfig.paymentConfig || {};

// ─── CATALOGO ────────────────────────────────────────────────────────────────
var productosBackend = [];
try {
  var pNode = $('Buscar Productos Backend').first().json;
  if (pNode && pNode.products && Array.isArray(pNode.products)) productosBackend = pNode.products;
} catch(e) {}

var catalogoEstatico = Array.isArray(input.catalog) ? input.catalog : (Array.isArray(businessConfig.catalog) ? businessConfig.catalog : []);

var catalogText = '';
if (productosBackend.length > 0) {
  catalogText = 'CATALOGO REAL (habla SOLO de estos productos, con precios y datos exactos):\n';
  productosBackend.forEach(function(p) {
    catalogText += '- ' + p.name;
    if (p.category) catalogText += ' [' + p.category + ']';
    if (p.price) catalogText += ' — $' + Number(p.price).toLocaleString('es-CO') + ' COP';
    if (p.comparePrice && p.comparePrice > p.price) catalogText += ' (antes $' + Number(p.comparePrice).toLocaleString('es-CO') + ')';
    if (p.sku) catalogText += ' | SKU: ' + p.sku;
    if (p.stock !== null && p.stock !== undefined) {
      if (p.stock === 0) catalogText += ' [AGOTADO]';
      else if (p.stock <= 5) catalogText += ' [Ultimas ' + p.stock + ' unidades]';
    }
    if (p.available === false) catalogText += ' [NO DISPONIBLE]';
    if (p.description) catalogText += '\n  ' + String(p.description);
    catalogText += '\n';
  });
} else if (catalogoEstatico.length > 0) {
  catalogText = 'CATALOGO (habla SOLO de estos productos):\n';
  catalogoEstatico.forEach(function(item) {
    catalogText += '- ' + item.name;
    if (item.price) catalogText += ' — $' + Number(item.price).toLocaleString('es-CO') + ' COP';
    if (item.category) catalogText += ' [' + item.category + ']';
    if (item.description) catalogText += ': ' + String(item.description).substring(0, 100);
    if (item.available === false) catalogText += ' [NO DISPONIBLE]';
    catalogText += '\n';
  });
} else {
  catalogText = 'No hay productos en el catalogo por el momento.';
}

// ─── FAQ ─────────────────────────────────────────────────────────────────────
var faqItems = Array.isArray(input.faq) ? input.faq : (Array.isArray(businessConfig.faq) ? businessConfig.faq : []);
var faqText = faqItems.length > 0
  ? faqItems.map(function(f) { return 'P: ' + f.question + '\nR: ' + f.answer; }).join('\n\n')
  : 'Sin preguntas frecuentes.';

// ─── ACCIONES Y RESTRICCIONES ─────────────────────────────────────────────────
var allowedText = Array.isArray(input.allowedActions) && input.allowedActions.length > 0
  ? input.allowedActions.map(function(a) { return '- ' + a; }).join('\n')
  : '- Informar sobre productos y precios\n- Tomar pedidos';

var restrictText = Array.isArray(input.restrictions) && input.restrictions.length > 0
  ? input.restrictions.map(function(r) { return '- ' + r; }).join('\n')
  : '- No revelar informacion confidencial';

// Palabras prohibidas del negocio
var prohibitedWords = Array.isArray(businessConfig.prohibitedWords) ? businessConfig.prohibitedWords : [];
if (prohibitedWords.length > 0) {
  restrictText += '\n- PALABRAS PROHIBIDAS (nunca usar estas palabras): ' + prohibitedWords.join(', ');
}

// ─── UBICACION ───────────────────────────────────────────────────────────────
var addressParts = [];
var ba = businessConfig.businessAddress || {};
if (ba.street) addressParts.push(ba.street);
if (ba.city) addressParts.push(ba.city.trim());
if (ba.state) addressParts.push(ba.state.trim());
if (ba.reference) addressParts.push('Ref: ' + ba.reference);
var locationText = addressParts.length > 0
  ? addressParts.join(', ')
  : (input.location || businessConfig.location || '');

// ─── HORARIO REAL DEL NEGOCIO ─────────────────────────────────────────────────
var hoursText = '';
var bhConfig = businessConfig.businessHours || input.businessHours || {};
if (bhConfig.schedule && Array.isArray(bhConfig.schedule)) {
  hoursText = '\n\nHORARIO DE ATENCION:\n';
  bhConfig.schedule.forEach(function(day) {
    if (day.isOpen) {
      hoursText += day.day + ': ' + day.open + ' - ' + day.close + '\n';
    } else {
      hoursText += day.day + ': Cerrado\n';
    }
  });
  if (bhConfig.timezone) hoursText += '(Zona horaria: ' + bhConfig.timezone + ')\n';
}

// ─── AGENTES HUMANOS ──────────────────────────────────────────────────────────
var humanAgentsText = '';
var allAgents = Array.isArray(input.humanAgents) ? input.humanAgents : (Array.isArray(businessConfig.humanAgents) ? businessConfig.humanAgents : []);
var availableAgents = allAgents.filter(function(a) { return a.available; });
if (availableAgents.length > 0) {
  humanAgentsText = '\n\nESCALACION A AGENTE HUMANO:\n';
  humanAgentsText += 'Si el cliente pide hablar con una persona, lo solicita explicitamente, o la situacion es compleja, indica que puede contactar a:\n';
  availableAgents.forEach(function(a) {
    humanAgentsText += '- ' + a.name + ': ' + a.phone + '\n';
  });
  humanAgentsText += 'Nunca inventes informacion que no tienes — ofrece escalar al agente humano si no puedes resolver.\n';
}

// ─── METODOS DE PAGO ──────────────────────────────────────────────────────────
var paymentMethodsText = Array.isArray(input.paymentMethods) && input.paymentMethods.length > 0
  ? input.paymentMethods.join(', ')
  : '';

// ─── DATOS BANCARIOS ─────────────────────────────────────────────────────────
var hasQrImage = !!(paymentConfig.qrImageUrl);
var paymentBankText = '';
if (paymentConfig.accountNumber || hasQrImage) {
  paymentBankText = '\n\nDATOS PARA PAGO:\n';
  if (paymentConfig.bankName) paymentBankText += '- ' + paymentConfig.bankName + ': ' + (paymentConfig.accountNumber || '') + '\n';
  if (paymentConfig.accountHolder) paymentBankText += '- Titular: ' + paymentConfig.accountHolder + '\n';
  var tipo = paymentConfig.accountType === 'checking' ? 'Cuenta Corriente' : 'Cuenta Ahorros';
  if (paymentConfig.accountNumber) paymentBankText += '- Tipo: ' + tipo + '\n';
  if (hasQrImage) paymentBankText += '- QR de pago disponible (se envia automaticamente)\n';
}

// ─── ENTREGA ─────────────────────────────────────────────────────────────────
var deliveryFee = salesConfig.deliveryFee || 0;
var deliveryType = salesConfig.deliveryType || 'both';
var deliveryText = '';
if (deliveryFee > 0) deliveryText += '\nCosto de domicilio: $' + Number(deliveryFee).toLocaleString('es-CO') + ' COP\n';
if (deliveryType === 'pickup') deliveryText += 'Solo recogida en tienda.\n';
else if (deliveryType === 'delivery') deliveryText += 'Solo domicilio a domicilio.\n';

// ─── DATOS REQUERIDOS DEL CLIENTE ────────────────────────────────────────────
var requireCustomerName = salesConfig.requireCustomerName === true;
var requireCustomerAddress = salesConfig.requireCustomerAddress === true;
var requireCustomerId = salesConfig.requireCustomerId === true;
var confirmationInstructions = salesConfig.confirmationInstructions || '';

var requiredFields = [];
if (requireCustomerName) requiredFields.push('Nombre completo del cliente');
if (requireCustomerId) requiredFields.push('Numero de cedula o documento de identidad');
if (requireCustomerAddress) requiredFields.push('Direccion completa de entrega (calle/carrera + barrio + ciudad + referencia en un solo campo)');

var dataRulesText = '';
if (requiredFields.length > 0) {
  dataRulesText += '\n\n=== FLUJO DE PEDIDO — REGLAS ABSOLUTAS ===\n';
  dataRulesText += 'ESTAS REGLAS ANULAN cualquier otro flujo de pedido mencionado en las instrucciones del negocio.\n\n';
  dataRulesText += 'PASO 1 — SELECCION DEL PRODUCTO:\n';
  dataRulesText += 'Cuando el cliente quiere comprar, asegurate de tener claro: producto + talla (si aplica).\n';
  dataRulesText += 'Si no ha mencionado la talla y el producto la requiere, pregunta primero.\n\n';
  dataRulesText += 'PASO 2 — DATOS DEL CLIENTE (pide estos ' + requiredFields.length + ' datos):\n';
  requiredFields.forEach(function(f, i) { dataRulesText += (i+1) + '. ' + f + '\n'; });
  dataRulesText += '\nREGLAS ESTRICTAS:\n';
  dataRulesText += '- Pide TODOS los datos faltantes en un solo mensaje.\n';
  dataRulesText += '- RECOLECCION INCREMENTAL: cuando el cliente proporcione datos parciales, confirma exactamente lo recibido y pide SOLO lo que falta.\n';
  dataRulesText += '- NO vuelvas a pedir un dato que el cliente ya proporciono en mensajes anteriores.\n';
  dataRulesText += '- NO inventes ni asumas datos del cliente.\n';
  dataRulesText += '- La ciudad de entrega ya esta incluida en la direccion completa, NO la pidas por separado.\n';
  dataRulesText += '- NO pidas metodo de pago por separado; el negocio acepta los metodos ya informados.\n\n';
  dataRulesText += 'PASO 3 — CONFIRMACION DEL PEDIDO:\n';
  dataRulesText += 'Cuando tengas el producto (+ talla) + los ' + requiredFields.length + ' datos del cliente:\n';
  dataRulesText += '1. Escribe [ENVIAR_QR] como PRIMERA linea (antes de cualquier texto)\n';
  dataRulesText += '2. Confirma el resumen completo del pedido:\n';
  dataRulesText += '   - Producto y talla\n';
  dataRulesText += '   - Datos del cliente (nombre, cedula, direccion)\n';
  dataRulesText += '   - Total: precio del producto + costo domicilio ($' + Number(deliveryFee).toLocaleString('es-CO') + ' COP)\n';
  dataRulesText += '3. Indica los datos de pago e informa que se envia el QR\n';
  dataRulesText += '4. Solicita el comprobante de pago para finalizar\n';
  if (confirmationInstructions) {
    dataRulesText += '\nGuia adicional del negocio:\n' + confirmationInstructions + '\n';
  }
}

// ─── QR DE PAGO ───────────────────────────────────────────────────────────────
var qrInstructionText = '';
if (hasQrImage) {
  qrInstructionText = '\n\n=== ENVIO DEL QR DE PAGO ===\n';
  qrInstructionText += 'Escribe [ENVIAR_QR] como PRIMERA linea en estos casos:\n';
  qrInstructionText += '1. Al confirmar el pedido completo (PASO 3 de arriba)\n';
  qrInstructionText += '2. Cuando el cliente pregunta sobre: pago, transferencia, Nequi, Bancolombia, QR, como pagar\n';
  qrInstructionText += 'Formato: [ENVIAR_QR]\n(tu respuesta aqui)\n';
}

// ─── CONFIRMACION DE VENTA (pago recibido) ────────────────────────────────────
var confirmationTagText = '';
if (paymentConfig.confirmationMethod === 'manual' || !paymentConfig.confirmationMethod) {
  confirmationTagText = '\n\n=== CUANDO EL CLIENTE CONFIRME EL PAGO ===\n';
  confirmationTagText += 'SOLO cuando el cliente envie comprobante de pago, foto de transferencia, o diga explicitamente que ya pago,\n';
  confirmationTagText += 'escribe en la PRIMERA linea:\n';
  confirmationTagText += '[VENTA_CONFIRMADA]{{"clientName":"<nombre completo>","clientId":"<cedula>","clientAddress":"<direccion>","productName":"<producto>","productDetails":"<talla/color>","quantity":1,"totalAmount":null,"paymentMessage":"<descripcion breve del pago>"}}\n';
  confirmationTagText += 'Luego el mensaje de agradecimiento al cliente.\n';
  confirmationTagText += 'SOLO usar [VENTA_CONFIRMADA] cuando el pago este confirmado — NO antes.\n';
  confirmationTagText += 'JSON con comillas dobles, null para valores desconocidos.';
}

// ─── FORMATO WHATSAPP ─────────────────────────────────────────────────────────
var formatRules = '\n\n=== FORMATO DE RESPUESTA (OBLIGATORIO) ===\n';
formatRules += 'Estas conversando por WhatsApp. Usa SOLO formato compatible con WhatsApp:\n';
formatRules += '- Negrilla: *texto* (UN solo asterisco por lado, NO dos **)\n';
formatRules += '- Italica: _texto_\n';
formatRules += '- NO uses ## headings, NO uses **texto**, NO uses markdown de GitHub/HTML\n';
formatRules += '- Cuando el cliente pregunta por un producto especifico, incluye TODA la informacion disponible:\n';
formatRules += '  * Nombre, precio, descripcion completa\n';
formatRules += '  * Tallas disponibles (todas las que esten en la descripcion)\n';
formatRules += '  * Colores disponibles\n';
formatRules += '  * Materiales y caracteristicas\n';
formatRules += '  * Stock si es limitado\n';
formatRules += 'Ejemplo de formato correcto para producto:\n';
formatRules += '*Chaqueta Windbreaker White Atlas*\n';
formatRules += 'Precio: $188.994 COP\n';
formatRules += 'Descripcion: [descripcion completa]\n';
formatRules += 'Tallas: S, L, XL\n';
formatRules += 'Colores: Blanco\n';

// ─── MENSAJE SISTEMA ─────────────────────────────────────────────────────────
var systemMessage =
  (input.aiInstructions || businessConfig.aiInstructions || 'Eres un asistente de ventas profesional y amable.') +
  '\n\nCliente en esta conversacion: ' + (input.pushName || 'Cliente') +

  formatRules +
  dataRulesText +

  '\n\n' + catalogText +
  '\n\nFAQ:\n' + faqText +
  (paymentMethodsText ? '\n\nMETODOS DE PAGO ACEPTADOS: ' + paymentMethodsText : '') +
  (locationText ? '\n\nUBICACION DE LA TIENDA: ' + locationText : '') +
  hoursText +
  deliveryText +
  paymentBankText +
  humanAgentsText +
  qrInstructionText +
  confirmationTagText +

  '\n\nACCIONES PERMITIDAS:\n' + allowedText +
  '\n\nRESTRICCIONES:\n' + restrictText +
  '\n\nMENSAJE DEL CLIENTE: "' + (input.message || '') + '"';

return [{
  json: {
    phone: input.phone,
    tenantId: input.tenantId,
    instanceName: input.instanceName,
    pushName: input.pushName,
    message: input.message,
    intent: input.intent,
    confidence: input.confidence,
    evolutionApiUrl: input.evolutionApiUrl,
    evolutionApiKey: input.evolutionApiKey,
    tenantEmail: input.tenantEmail || '',
    businessName: businessConfig.businessName || input.businessName || '',
    paymentQrImageUrl: paymentConfig.qrImageUrl || '',
    systemMessage: systemMessage
  }
}];

const input = $('Preparar Contexto Ventas').first().json;
const aiOutput = $input.first().json;
let response = aiOutput.output || aiOutput.text || 'Lo siento, no pude procesar tu consulta de ventas.';

// Detectar [ENVIAR_QR] tag — el sistema enviara la imagen QR al cliente
const sendQrImage = response.includes('[ENVIAR_QR]') && !!(input.paymentQrImageUrl);
if (response.includes('[ENVIAR_QR]')) {
  response = response.replace('[ENVIAR_QR]', '').trim();
}

// Detectar confirmacion de venta y parsear JSON estructurado
const saleConfirmed = response.trimStart().startsWith('[VENTA_CONFIRMADA]');
let saleData = {};
if (saleConfirmed) {
  const withoutTag = response.replace('[VENTA_CONFIRMADA]', '').trim();
  const jsonMatch = withoutTag.match(/^(\{[\s\S]*?\})(\s*[\s\S]*)$/);
  if (jsonMatch) {
    try {
      saleData = JSON.parse(jsonMatch[1]);
    } catch(e) {
      // JSON invalido — continuar sin datos estructurados
    }
    response = jsonMatch[2].trim();
  } else {
    response = withoutTag;
  }
}

let imagenProductoUrl = null;
try {
  const specificProds = $('Buscar Producto Especifico').first().json.products || [];
  const allProds = $('Buscar Productos Backend').first().json.products || [];
  const responseLower = response.toLowerCase();
  // Show image ONLY when full product name appears verbatim in the AI response
  const findByName = function(prods) {
    return prods.find(function(p) {
      if (!p.imageUrl || !p.name) return false;
      return responseLower.includes(p.name.toLowerCase());
    });
  };
  const matched = findByName(specificProds) || findByName(allProds);
  if (matched) imagenProductoUrl = matched.imageUrl;

  // Suprimir imagen en modo recoleccion de datos del cliente
  if (imagenProductoUrl) {
    const isCollectingData =
      /[1-4]\\.\\s*(nombre|cedula|direccion|documento|identidad|talla)/i.test(response) ||
      (/(necesito|necesitare|proporciona|para.*compra.*datos|datos.*pedido)/i.test(response) && /(cedula|direccion|nombre)/i.test(response));
    if (isCollectingData) imagenProductoUrl = null;
  }

  // Suprimir imagen cuando el bot lista el catalogo completo (3+ productos mencionados)
  if (imagenProductoUrl) {
    const allProdNames = allProds.map(function(p) { return p.name ? p.name.toLowerCase() : ''; });
    const mentionCount = allProdNames.filter(function(n) { return n && responseLower.includes(n.split(' ')[0]); }).length;
    if (mentionCount >= 3) imagenProductoUrl = null;
  }

  // Suprimir imagen cuando el bot confirma pedido y ya envio QR (evitar doble envio)
  if (imagenProductoUrl && sendQrImage) imagenProductoUrl = null;
} catch(e) {}

return [{ json: {
  response, saleConfirmed, sendQrImage,
  saleData,
  imagenProductoUrl,
  intent: saleConfirmed ? 'sale_confirmed' : 'ventas',
  tokensEstimated: Math.ceil(((input.message||'') + response).length / 4),
  phone: input.phone,
  tenantId: input.tenantId,
  tenantEmail: input.tenantEmail || '',
  businessName: input.businessName || '',
  paymentQrImageUrl: input.paymentQrImageUrl || '',
  instanceName: input.instanceName,
  evolutionApiUrl: input.evolutionApiUrl || '',
  evolutionApiKey: input.evolutionApiKey || '',
  intent_handled: saleConfirmed ? 'sale_confirmed' : 'ventas',
  action_taken: saleConfirmed ? 'venta_confirmada' : 'respuesta_generada',
  metadata: { pushName: input.pushName, original_message: input.message }
} }];

const input = $('Recibir Datos del Router').first().json;
const prodData = $('Buscar Productos Backend').first().json;
const prods = (prodData.products || input.catalog || []).slice(0, 15);

// Detectar si el cliente esta enviando un comprobante de pago:
// Caso 1: imagen sin texto (message = '[imagen]') — puede ser comprobante
// Caso 2: imagen con texto que menciona pago/comprobante/transferencia
const caption = input.message && input.message !== '[imagen]' ? input.message : '';
const isPaymentReceipt = /comprobante|pago|transferencia|nequi|bancolombia|pague|pagué|ya pag|realice|realicé|hice.*pago|aqui.*pago|pago.*adjunto|soporte.*pago/i.test(caption);
const isOnlyImage = !caption || caption === '[imagen]';

// Si es comprobante explícito O imagen sola (contexto de pago activo),
// pasar directo al agente de ventas como mensaje especial — no Vision
if (isPaymentReceipt || isOnlyImage) {
  const paymentMsg = isPaymentReceipt
    ? caption + ' [IMAGEN_ADJUNTA: comprobante de pago]'
    : '[IMAGEN_ADJUNTA: el cliente envió una imagen — posiblemente comprobante de pago]';
  // Retornar señal para que el nodo salte Vision y vaya al agente
  return [{ json: {
    skipVision: true,
    paymentMessage: paymentMsg,
    openAiBody: null,
    prods,
    phone: input.phone,
    tenantId: input.tenantId,
    instanceName: input.instanceName,
    pushName: input.pushName,
    evolutionApiUrl: input.evolutionApiUrl || '',
    evolutionApiKey: input.evolutionApiKey || ''
  } }];
}

// Imagen que NO es comprobante → analizar con Vision para identificar producto
const catalogText = prods.length > 0
  ? prods.map(p => {
      let line = '• ' + p.name;
      if (p.category) line += ' [' + p.category + ']';
      if (p.price) line += ' — $' + Number(p.price).toLocaleString('es-CO');
      if (p.description) line += ': ' + String(p.description).substring(0, 80);
      if (p.available === false) line += ' [NO DISPONIBLE]';
      return line;
    }).join('\n')
  : 'Sin catálogo configurado.';
const businessName = input.businessName || 'nuestra tienda';
const thumbnail = input.imageThumbnailBase64 || '';
const systemContent = `Eres un experto en ventas de ${businessName}. Analiza la imagen y responde SOLO en JSON con este formato exacto: {"producto_catalogo": "nombre exacto del producto si coincide con el catálogo o null si no hay coincidencia", "respuesta": "respuesta cálida y comercial en español"}`;
const userContent = [];
if (thumbnail) {
  userContent.push({ type: 'image_url', image_url: { url: 'data:image/jpeg;base64,' + thumbnail, detail: 'low' } });
}
userContent.push({ type: 'text', text: `${caption ? 'El cliente escribió: "' + caption + '". ' : ''}Catálogo disponible:\n${catalogText}\n\nIdentifica si el producto de la imagen coincide con alguno del catálogo y elabora una respuesta comercial.` });
const openAiBody = {
  model: 'gpt-4o',
  response_format: { type: 'json_object' },
  messages: [{ role: 'system', content: systemContent }, { role: 'user', content: userContent }],
  max_tokens: 500
};
return [{ json: { skipVision: false, openAiBody, prods, phone: input.phone, tenantId: input.tenantId, instanceName: input.instanceName, pushName: input.pushName, evolutionApiUrl: input.evolutionApiUrl || '', evolutionApiKey: input.evolutionApiKey || '' } }];

const ctx = $('Preparar Request Imagen').first().json;
const apiResp = $input.first().json;
let responseText, productoCatalogo = null;
try {
  const raw = apiResp.choices?.[0]?.message?.content || '{}';
  const parsed = JSON.parse(raw);
  responseText = parsed.respuesta || raw;
  productoCatalogo = parsed.producto_catalogo || null;
} catch(e) {
  responseText = apiResp.choices?.[0]?.message?.content || '¡Hola! Recibí tu imagen. ¿Qué producto buscas?';
}
let imagenProductoUrl = null;
if (productoCatalogo && ctx.prods && ctx.prods.length > 0) {
  const lc = productoCatalogo.toLowerCase().trim();
  const match = ctx.prods.find(p => p.name && (p.name.toLowerCase().includes(lc) || lc.includes(p.name.toLowerCase())));
  if (match && match.imageUrl) imagenProductoUrl = match.imageUrl;
}
return [{ json: { response: responseText, imagenProductoUrl: imagenProductoUrl, phone: ctx.phone, tenantId: ctx.tenantId, instanceName: ctx.instanceName, evolutionApiUrl: ctx.evolutionApiUrl, evolutionApiKey: ctx.evolutionApiKey, intent: 'ventas', intent_handled: 'ventas', action_taken: 'imagen_analizada', metadata: { pushName: ctx.pushName, producto_identificado: productoCatalogo } } }];

const router = $('Recibir Datos del Router').first().json;
const pdfData = $('Obtener Catalogo PDF').first().json;
const businessName = router.businessName || 'nuestros productos';
return [{
  json: {
    evolutionUrl: router.evolutionApiUrl + '/message/sendMedia/' + router.instanceName,
    evolutionApiKey: router.evolutionApiKey,
    requestBody: {
      number: router.phone,
      mediatype: 'document',
      mimetype: 'application/pdf',
      caption: 'Catalogo de ' + businessName,
      media: pdfData.pdfUrl,
      fileName: pdfData.fileName || 'catalogo.pdf'
    },
    phone: router.phone,
    tenantId: router.tenantId,
    pushName: router.pushName,
    businessName: businessName
  }
}];

const ctx = $('Preparar Envio PDF').first().json;
return [{
  json: {
    response: 'Listo, ' + (ctx.pushName || 'estimado cliente') + '! Te acabo de enviar el catalogo de ' + (ctx.businessName || 'nuestra tienda') + ' en PDF.\n\nHay algun producto que te llame la atencion? Con gusto te ayudo con precios, disponibilidad o para coordinar tu pedido.',
    phone: ctx.phone,
    tenantId: ctx.tenantId,
    intent: 'ventas',
    intent_handled: 'ventas',
    action_taken: 'catalogo_pdf_enviado',
    metadata: { pushName: ctx.pushName }
  }
}];

const input = $('Recibir Datos del Router').first().json;
const prods = (input.catalog || []);
const catalogLines = prods.slice(0, 10).map(p => {
  let line = `• *${p.name}*`;
  if (p.price) line += ` — $${Number(p.price).toLocaleString('es-CO')}`;
